import{_ as p,o as e,c as a,j as r,a as t,a1 as m}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"神秘学者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/神秘学者.md","filePath":"4.资源分区/4.术法/魔法/神秘学者.md"}'),n={name:"4.资源分区/4.术法/魔法/神秘学者.md"};function s(o,b,d,l,D,_){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"神秘学者",tabindex:"-1"},[t("神秘学者 "),r("a",{class:"header-anchor",href:"#神秘学者","aria-label":'Permalink to "神秘学者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),m('<h1 id="神秘学者-1" tabindex="-1">神秘学者 <a class="header-anchor" href="#神秘学者-1" aria-label="Permalink to &quot;神秘学者&quot;">​</a></h1><p>神秘学者<br> 曾被企图掌握其可怕力量的帝国军队追捕，神秘学者的技艺着重于召唤与借用三大巫神拜斯迈，索拉尔和德利格所赐予的力量，他们的多重技艺包括诅咒和能造成毒素，酸性和腐蚀伤害的技能。即使不擅长剑与枪械，他们仍然可以借用其中任意一种来增强攻击。</p><p>熵能<br> 熵能池：开启熵能池，关键属性为智力+感知，每天自动回复三倍上限的能量，平均到每时每分每秒。不获得基础用法。<br> 基础运用：你获得了一个新的攻击方式，检定为【智力+专注+专业：仪式构建+专业：仪式操控】，射程15m，造成负能量伤害。</p><p>学生<br> D+1000<br> 基础学识：获得专注下专业：仪式构建1级，以及洞察下专业：仪式操控1级。<br> 熵能：开启熵能池，并获得基础用法。</p><p>学士<br> C+1000<br> 进阶学识：若专注或洞察不满3级，则为它们任意分配3个等级，但不能使其超过3级；若专注或洞察达到3级，则可以选择一个使其提升1级。然后再为专业：仪式构建和专业：仪式操控任意分配3个等级。<br> 仪式熟练：熟练掌握了神秘学识的学士，能够更加容易的创建巫术仪式。仪式构建检定增加3DP修行加值和1修行附加成功。</p><p>导师<br> B+2000<br> 专家学识：专注和洞察技能提升1级，专业：仪式构建和专业：仪式操控提升3级。<br> 仪式精通：经过长期的研究和使用，神秘导师可以轻易用许多构建技巧增强神秘仪式的效果。仪式构建检定时增加6DP修行加值和【9加骰】，若该次检定已经具有【9加骰】，则改为【8加骰】，若已有【8加骰】则改为增加2修行附加成功。</p><p>巫火系：<br> 索拉尔的巫火<br> D+500<br> 驾驭索拉尔的邪术力量，使熵能在每一次武器攻击中灼烧敌人。<br> 花费自由动作开启，消耗2点熵能，持续一小时，神秘学者的攻击额外具有3负能量加值，额外造成1点负能量伤害。你不能重复获得巫火带来的所有好处。<br> 进阶：<br> D+500<br> 消耗6点熵能，持续一天，神秘学者的攻击额外具有6负能量加值，额外造成2点负能量伤害。</p><p>祭祀之剑<br> 250<br> 巫火吞噬你的武器，以混沌能量凝聚其身。<br> 索拉尔的巫火开启时，神秘学者使用刀剑与枪械造成的伤害变为负能量伤害。</p><p>二次仪式<br> 前置：索拉尔的巫火<br> C+1000<br> 加深神秘学者与隐秘国度之间的联系，使巫火的力量变得更为强大，哪怕是最为轻微的接触也足以让敌人的魔法能量燃烧殆尽。<br> 索拉尔的巫火开启时，神秘学者的攻击会燃烧敌人4点能量，意志豁免。<br> 进阶：<br> C+1000<br>     神秘学者的攻击将会燃烧敌人8点能量，意志豁免。</p><p>魔印系：<br> 噬命魔印<br> C+1000<br> 在地面上施放一种神秘的印记，它将吞噬深陷其中的敌人的生命力。造成的伤害将以一定比例转化为生命返还给神秘学者。<br> 花费标准动作，消耗3点熵能，以【智力+专注+专业：仪式构建+专业：仪式操控】进行攻击检定，在距离自己最远25m的地点上施放一个圆形印记，对半径4m范围内的敌人造成负能量伤害，本次攻击具有【吸血4】。</p><p>进阶：<br> C+1250<br>     距离不变，范围半径变为7.5m，【吸血4】变为【吸血8】，以意志豁免对抗伤害。</p><p>毁灭<br> 前置：噬命魔印<br> D+750<br> 将混沌本身蕴含的毁灭之力注入魔印之中。<br>     噬命魔印的攻击额外造成1点负能量伤害，同时具有3点破魔。<br> 进阶：<br> D+500<br>     噬命魔印的攻击额外造成2点负能量伤害，同时具有6点破魔，1点高速。</p><p>邪眼系：<br> 德利格之眼<br> D+500<br> 召唤隐秘国度的守护者德利格所拥有的无数只邪眼中的一只，它将迅速飞向敌人，然后引爆自身。<br> 花费标准动作，消耗2点熵能，以【智力+专注+专业：仪式构建+专业：仪式操控】进行攻击检定，释放一颗邪眼冲向距离自己最远20m的敌人，命中后邪眼爆裂开来，喷溅的毒血，造成一半毒性，一半腐蚀伤害。本次攻击具有【高速5】【法破】，以及3DP技艺加值（</p><p>血爆<br> 前置：德利格之眼<br> D+500<br>     神秘的邪眼在命中敌人时爆炸，向周围的敌人喷溅毒血。<br> 德利格之眼现在改为对最远10m的目标半径2.5m范围内所有敌人造成伤害，本次攻击额外获得3DP技艺加值。</p><p>聚能凝视<br> 前置：血爆<br> C+1000<br> 将德利格的邪恶力量引导至每只邪眼之中，使邪眼发生更为猛烈的爆炸，造成更多的伤害。<br> 德利格之眼的消耗增加1点，影响半径变为5m，攻击具有【9加骰】【接触攻击】特性</p><p>恐惧凝视<br> 前置：血爆<br> C+1000<br> 不朽又可畏的巫神德利格，面对他那令人恐惧的凝视，敌人要么惊恐的呆在原地，要么直接逃之夭夭。<br> 德利格之眼距离增加40m，同时攻击附带等于伤害的恐惧点数。</p><p>邪物喷涌<br> 前置：恐惧凝视<br> B+2000<br> 邪眼撞上敌人时会炸出腐败的碎块，不幸身处爆炸范围内的敌人会遭受更深的痛楚。<br> 邪眼的熵能消耗变为6，距离增加20m，技艺加值再增加9DP，【9加骰】变为【8加骰】，攻击附带等于成功数的毒素点数，现在本攻击的伤害完全变为腐蚀伤害。</p><p>瘟疫系：<br> 血瘟疫<br> D+500<br> 这种恶毒的，连众多神秘学者都畏之三分的诅咒会在敌人之中传播致命的瘟疫，进而不可逆转地掏空他们的生命力，他们的每个毛孔都将血流不止。<br> 花费标准动作，消耗2点熵能，以【智力+专注+专业：仪式构建+专业：仪式操控】进行攻击检定，对最远15m的目标造成毒素伤害，并附带3点流血点数，这都视为疾病来源。</p><p>狂热怒意<br> 前置：血瘟疫<br> D+500<br> 血瘟疫的变异对敌人和神秘学者本身来说都很危险。血瘟疫将极快地发作，不但会使造成的伤害倍增，更会令敌人患上高热，变得癫狂无比。<br> 血瘟疫附带的流血点数上升1点，并额外附带等于成功数的亢奋点数，本次攻击额外获得【法破】特性。</p><p>恶疾<br> 前置：狂热怒意<br> C+1000<br> 血瘟疫将摧毁敌人的活力，即使是流出的眼泪也将变为大片的鲜血。如此阴险的巫术使神秘学者变得臭名昭著，所以许多神秘学者都死在了火刑柱上。<br> 血瘟疫的消耗上升1点，施放距离不变，不再造成毒素伤害，而是完全转化为成功数+4点流血点数，同时血瘟疫获得自发传播的能力，在目标4m范围内，通过飞沫、空气、皮肤接触途径传播给其他敌人。</p><p>黑死病<br> 前置：恶疾<br> B+2000<br> 身体的高热和内脏的溶解折磨着敌人，使他们在战场上的攻击落空，甚至攻击他们的队友。<br> 血瘟疫消耗上升4点，施放距离增加100m，传染范围增加至20m，额外造成A级混乱效果，使其攻击除了自己的友方。同时本攻击具有6DP技艺加值。</p><p>诅咒：<br> 虚弱诅咒<br> D+500<br> 强大而无情的咒语使敌人失去勇气，使他们变得缓慢而脆弱。<br> 花费移动动作，消耗2点熵能，对最远15m的目标降下诅咒，使其移速下降10m，决心检定和豁免检定获得2DP士气减值，持续一小时。</p><p>易伤<br> 前置：虚弱诅咒<br> D+500<br> 增强诅咒蕴含的邪力，以至于诅咒能够弱化敌人的体质，让他们无力抵抗巫术与毒药。<br> 虚弱诅咒的熵能消耗上升2点，距离增加10m，目标的耐力和豁免检定获得3DP增强减值。</p><p>祝福：<br> 德利格之血<br> C+1000<br> 与伟大守护者之间的精神联系将赐予你一部分德利格的恢复能力，受到敌人攻击时将喷溅出巫神德利格身上的毒血。<br> 花费移动动作，消耗4点熵能，使半径4m范围内友方增加【快速治疗3】【36医疗点】，持续1小时。</p><p>守护者的躯体<br> 前置：德利格之血<br> BC+1000<br> 花费迅捷动作，消耗熵能提升到8点，影响范围扩大到半径15m，【快速治疗】提升到【快速治疗6】【医疗点72】，并额外获得【异常点治疗3】【72医疗点】，同时可以立即再生四肢，持续一小时。</p><p>鸦灵：<br> 召唤乌鸦<br> C+2000<br> 召唤神话中的风暴乌鸦来援助你。<br> 花费标准动作，消耗6点熵能，召唤一只D级的风暴乌鸦，上限1只，自由行动，持续1小时。死亡后可再次召唤。</p><p>风暴乌鸦<br> 风暴乌鸦是与寻常的乌鸦不同的一种拥有不可思议的智慧和魔力的奇异生物。有些人坚信它们不是鸟，而是以乌鸦的形式现身的某种古老的天空之灵。</p><p>▓智力6 ▓感知6 ▓决心6<br> ▓力量2 ▓敏捷6 ▓耐力2<br> ▓风度2 ▓操控2 ▓沉着4</p><p>▓▓▓▓技能<br> ▓学识5（施法5，解读2）<br> ▓专注3（意志3）</p><p>▓运动3（反射3）<br> ▓求生3（强韧3）</p><p>▓洞察5（魔力感知5，侦察3，搜索2）<br> ▓隐秘3（潜藏2）</p><p>▓▓▓▓衍生属性值<br> ▓体积3（仅画风）<br> ▓速度16（力量2+敏捷6+体积5）<br> ▓先攻10（敏捷+沉着）<br> ▓防御 基础6（敏捷与感知中较低者+较高者的附加成功）<br> ▓生命值7（耐力+体积+耐力附加×2+耐力附加/2）<br> ▓意志力池12（决心+沉着+决心附加×2）<br> ▓意志12+1（决心+专注：意志）<br> ▓反射12+1（敏捷+运动：反射）<br> ▓强韧8（耐力+生存：强韧）<br> ▓侦查14+2（感知+洞察：侦查）<br> ▓敏感范围140（感知*20米+感知上的附加成功*20米）<br> ▓▓▓▓攻击预设：<br> 风暴光球：智力6+学识5+施法5+魔力感知5+能量3=24+3【法破】【能量武器】</p><p>▓▓▓▓防御预设：</p><p>魔力：12/12</p><p>魔力：开启魔力池，关键属性为智力+感知。（基础3）<br> 风暴光球：花费标准动作，使用【智力+学识+专业：施法+专业：魔力感知】进行施法检定，对最远智力m的目标造成成功数点雷电伤害，本次攻击具有【法破】【能量武器】特性，并具有3DP能量加值和1能量附加成功。</p><p>飞行：风暴乌鸦具有普通飞行能力。<br> 额外属性：感知+2，决心+2。</p><p>以下风暴乌鸦技能的兑换会如常给予乌鸦内在属性，自由分配。<br> 血肉缝合<br> D+500<br> 乌鸦引导神秘能量治疗受伤的盟友。<br> 乌鸦花费标准动作，消耗1点魔力，给予15m内一个友方【快速治疗2】【医疗点32】，持续一小时，同时仅能给予一个人。</p><p>风暴之心<br> C+1000<br> 乌鸦能向选中的盟友注入神秘的能量，授予他们超凡的能力。<br> 乌鸦花费移动动作，给予4m内友方闪电的力量，使其攻击额外造成2点雷电伤害，并获得1点能量附加成功。同时获得5雷电抗力。持续一小时。</p><p>闪电打击<br> B+2000<br> 风暴乌鸦召唤强力的闪电来攻击附近的敌人。<br> 乌鸦花费标准动作，消耗5点魔力，使用【智力+学识+专业：施法+专业：魔力感知】进行施法检定，对智力m半径锥形范围内的敌人造成雷电伤害，附带等同伤害的眩晕点数，强韧豁免；本次攻击具有【法破】【能量武器】【接触攻击】特性，以及1点能量附加成功。</p><p>地狱犬：<br> 召唤地狱猎犬<br> B+4000<br> 从神秘国度中召唤出一只地狱猎犬撕咬神秘学者的敌人。<br> 花费标准动作，消耗6点熵能，召唤1只C级的地狱犬，自由行动，持续1小时。死亡后可再次召唤。</p><p>地狱猎犬<br> 这种邪恶的野兽将跟随在你身旁战斗直至生命在火焰地狱里终结。</p><p>▓智力6 ▓感知9 ▓决心9 <br> ▓力量11 ▓敏捷11 ▓耐力9 <br> ▓风度6 ▓操控6 ▓沉着6</p><p>▓▓▓▓技能 <br> ▓学识5（武学掌握5）<br> ▓专注5（意志5）</p><p>▓运动8（反射8，攀爬1，跳跃1，游泳1，平衡1）<br> ▓求生5（强韧5，追踪5）<br> ▓武技8（犬斗8）</p><p>▓洞察5（侦察5，搜索5）</p><p>▓▓▓▓衍生属性值 <br> ▓体积5<br> ▓速度33（力量+敏捷+体积） <br> ▓先攻d20+17（敏捷+沉着） <br> ▓防御 基础9（敏捷与感知中较低者+较高者的附加成功） <br> ▓生命值16（耐力+体积+耐力附加×2+耐力附加/2） <br> ▓意志力池17（决心+沉着+决心附加×2） <br> ▓意志19+2（决心+专注：意志） <br> ▓反射27+4（敏捷+运动：反射） <br> ▓强韧19+2（耐力+生存：强韧） <br> ▓侦查19+2（感知+洞察：侦查） <br> ▓敏感范围200（感知*20米+感知上的附加成功*20米） <br> ▓▓▓▓攻击预设： <br> 普攻=力量11+武技8+犬斗8+武学掌握5+武器伤害4=36+4【法破】【破甲5】</p><p>▓▓▓▓防御预设： <br> 常态=基础9+天防5=14【防弹】【防能量】【火焰抗性5】</p><p>地狱火：地狱犬体表和体内燃烧着不息的地狱之火，攻击附带3点燃烧点数，并且无视5点对火焰有效的能量抗力。<br> 尖牙利爪：地狱犬的牙齿和爪子视为伤害4L的天生武器，具有【法破】【破甲5】特性。<br> 地狱犬皮：地狱犬的皮肤不仅坚韧而且具有良好的能量抗性，获得5点天生防御，5点火焰能量抗性，并具有【防能量】【防弹】特性</p><p>以下地狱猎犬技能的兑换会如常给予猎犬内在属性，自由分配。<br> 灰烬之爪<br> B+2000<br> 在地狱猎犬可触及的范围内使用硫磺之爪在敌人身上撕扯出一道道烈焰之弧。<br> 花费标准动作进行一次范围攻击，对前方最远1米的扇形范围造成伤害，反射豁免。在本次攻击中，地狱火特性附带的固定燃烧点数改为附带等于伤害的燃烧点数。并具有6点技艺加值和2点技艺附加成功。</p><p>炼狱吐息<br> A+4000<br> 地狱猎犬向外喷吐地狱怒炎，将敌人烧成灰烬。<br> 花费标准动作向外喷吐烈焰，使用【敏捷+运动+喷吐+魔力爆发】进行攻击检定，对27.5米锥形范围内的敌人造成等于成功数的四档燃烧点数。本次攻击具有【9加骰】【法破】【接触攻击】。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',52)])])}const h=p(n,[["render",s]]);export{c as __pageData,h as default};
